import re

def checkAdminPassword(password):
    if len(password) < 12:
        return False
    if not re.search(r'[A-Z]', password):
        return False
    if not re.search(r'[a-z]', password):
        return False
    if not re.search(r'\d', password):
        return False
    if not re.search(r'[^a-zA-Z0-9]', password):
        return False
    if any(char.isspace() for char in password):
        return False
    common_passwords = {'password', '123456', 'admin', '123456789', 'qwerty', 'abc123', 'letmein', 'dragon', 'sunshine', 'iloveyou'}
    if password.lower() in common_passwords:
        return False
    return True

