import base64
import json

def confirmAuth(headers):
    token_str = headers.get('AuthToken')
    if not token_str:
        return None
    try:
        decoded = base64.b64decode(token_str)
        decoded_str = decoded.decode('utf-8')
        token_obj = json.loads(decoded_str)
        if token_obj.get('valid') is True:
            return token_obj.get('data')
        return None
    except (base64.binascii.Error, json.JSONDecodeError, UnicodeDecodeError):
        return None

